mapper.sql:
FROM stk_io_bill b
INNER JOIN stk_io_bill_entry e ON e.paren_id = b.id AND (e.del_flag IS NULL OR e.del_flag != 1)
LEFT JOIN fd_department d ON b.department_id = d.id AND d.tenant_id = b.tenant_id
LEFT JOIN fd_warehouse w ON b.warehouse_id = w.id AND w.tenant_id = b.tenant_id
LEFT JOIN fd_material m ON e.material_id = m.id AND m.tenant_id = b.tenant_id
WHERE b.tenant_id = #{tenantId}
  AND (b.del_flag IS NULL OR b.del_flag != 1)
  AND b.bill_type = #{billType}

    AND b.bill_type IN
    #{bt}

  AND b.bill_status = #{billStatus}
  AND b.bill_no LIKE CONCAT('%', #{billNo}, '%')

    AND (
      e.material_name LIKE CONCAT('%', #{materialName}, '%')
      OR m.name LIKE CONCAT('%', #{materialName}, '%')
    )


    AND (
      e.material_speci LIKE CONCAT('%', #{materialSpeci}, '%')
      OR m.speci LIKE CONCAT('%', #{materialSpeci}, '%')
    )


    AND d.name LIKE CONCAT('%', #{departmentName}, '%')


    AND w.name LIKE CONCAT('%', #{warehouseName}, '%')


    AND IFNULL(e.his_push_status, '0') = #{hisPushStatus}
